WORKSPACE_ID = 41811
BATCH_SIZE = 100


def execute(dry_run=True):
    print("=" * 80)
    print(f"{'DRY RUN MODE' if dry_run else 'LIVE MODE'}")
    print("=" * 80)
    total_deleted = 0
    total_batches = (len(CONTRACT_IDS) + BATCH_SIZE - 1) // BATCH_SIZE
    for batch_num in range(total_batches):
        start_idx = batch_num * BATCH_SIZE
        end_idx = start_idx + BATCH_SIZE
        batch_contract_ids = CONTRACT_IDS[start_idx:end_idx]
        print(f"\n[Batch {batch_num + 1}/{total_batches}]")
        print(f"Processing {len(batch_contract_ids)} contracts...")
        # Fetch key pointers for current batch
        contract_key_pointers = ContractKeyPointer.objects.filter(
            contract_id__in=batch_contract_ids, created_by_workspace=WORKSPACE_ID
        )
        count = contract_key_pointers.count()
        print(f"Found {count} key pointers")
        if count == 0:
            print("No key pointers to process, skipping...")
            continue
        if dry_run:
            print(f"[DRY RUN] Would delete {count} key pointers")
            print(
                f"[DRY RUN] Would resync {len(batch_contract_ids)} contracts to Elasticsearch"
            )
        else:
            deleted_count, _ = contract_key_pointers.delete()
            print(f"Successfully deleted {deleted_count} key pointers")
            # Resync contracts to Elasticsearch
            partially_resync_contracts_task.delay(
                contract_ids=batch_contract_ids, fields=KEY_POINTER_DERIVED_SEARCH_FIELDS
            )
            print(
                f"Triggered Elasticsearch resync for {len(batch_contract_ids)} contracts"
            )
        total_deleted += count
        if batch_num + 1 < total_batches:
            print("Sleeping 5 seconds before next batch...")
            time.sleep(5)
    print("\n" + "=" * 80)
    print(
        f"Total key pointers {'would be deleted' if dry_run else 'deleted'}: {total_deleted}"
    )
    if dry_run:
        print("\nDRY RUN - No data modified. Run execute(dry_run=False) to delete.")
    else:
        print(
            f"\nElasticsearch resync triggered for {len(CONTRACT_IDS)} contracts (async)"
        )
    print("=" * 80)


# Usage:
# execute()  # Dry run
# execute(dry_run=False)  # Actual delete
